const allRows = $input.all();
const pendingRow = allRows.find(r => r.json.Status && r.json.Status.toLowerCase().trim() === 'pending' && r.json.Keyword);

if (!pendingRow) {
  return [{ json: { hasPending: false, Keyword: '', Type: '', Location: '', row_number: 0 } }];
}

return [{
  json: {
    hasPending: true,
    Keyword: pendingRow.json.Keyword,
    Type: pendingRow.json.Type || 'long-tail',
    Priority: pendingRow.json.Priority || 'medium',
    Location: pendingRow.json.Location || 'Jackson, MS',
    row_number: pendingRow.json.row_number || 2
  }
}];

const kwData = $('Get Pending Keyword').first().json;
const brandVoiceRows = $('Read Brand Voice').all();

const keyword = kwData.Keyword;
const location = kwData.Location || 'Jackson, MS';
const kwType = kwData.Type || 'long-tail';
const rowNumber = kwData.row_number;

// Generate slug
const slug = keyword
  .toLowerCase()
  .replace(/[^a-z0-9\s-]/g, '')
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-')
  .trim();

// Determine category
let category = 'Local Guides';
if (kwType === 'informational') category = 'Tips & Guides';
if (kwType === 'neighborhood') category = 'Service Areas';

// Dates
const today = new Date().toISOString().split('T')[0];
const todayFormatted = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

// Brand voice
const brandVoice = brandVoiceRows
  .filter(r => r.json.Category && r.json.Guideline)
  .map(r => `- ${r.json.Category}: ${r.json.Guideline}`)
  .join('\n');

const prompt = `You are writing an SEO blog post for MidSouth Dumpster Rentals, a locally-owned dumpster rental company in Jackson, MS.

TARGET KEYWORD: "${keyword}"
SLUG: ${slug}
LOCATION: ${location}
CATEGORY: ${category}
DATE: ${todayFormatted}

BRAND VOICE RULES:
${brandVoice}

BUSINESS FACTS:
- Company: MidSouth Dumpster Rentals, LLC
- Phone: 601-316-7891 (same-day delivery if called before noon)
- Hours: 7AM-7PM, 7 days a week
- Address: 3080 B John R Lynch St, Jackson, MS 39209
- 10-yard: from $349 (1 ton limit) — garage cleanouts, small remodels
- 15-yard: from $399 (2 ton limit) — most popular, home renos, roofing
- 20-yard: from $449 (3 ton limit) — large renos, construction, demo
- Flat-rate pricing: delivery, pickup, disposal all included, no hidden fees
- Service areas: Jackson, Brandon, Madison, Clinton, Pearl, Ridgeland, Flowood, Byram, Terry, Raymond, Canton, Richland, Florence
- Booking: https://embed.survcart.com/?type=landing&co=irGaFVL6CggDRSyqIHNa&wsid=3u8ibIDlEWCk4uhSC1iS&sel=B77cgcBIlxlcSRgehUvF

STEP 1: Use tavily_search to research "${keyword}" — understand what searchers want, what competitors cover, local MS angle.

STEP 2: Write the complete blog post as a Next.js TSX file.

CRITICAL OUTPUT RULES:
- Return ONLY the raw TSX file content. No markdown fences. No explanations. No intro text.
- File must start with: import { Metadata } from 'next'
- ONLY allowed exports: export const metadata and export default function BlogPost. NO OTHER EXPORTS.
- NEVER add: export const postData, export const config, export const revalidate, or any other export besides metadata and the default function.
- All apostrophes in JSX text must be &apos; not '
- All & in JSX text must be &amp;
- NO dangerouslySetInnerHTML — write all content as real JSX elements, not HTML strings
- Use Link from next/link for internal links (already imported) — write actual Link elements, never [text](url) markdown
- Use <a href="tel:6013167891"> for phone links
- Post body: 900-1200 words of real, helpful content
- Include min 1 internal link to a service page: /services/10-yard-dumpster, /services/15-yard-dumpster, or /services/20-yard-dumpster
- Include min 1 internal link to a service area: /service-areas/jackson, /service-areas/brandon, /service-areas/madison, etc.
- 4-5 FAQ entries that address real questions people have about this topic
- End with CTA section using the booking link and phone number

TSX FILE TEMPLATE (fill in ALL [PLACEHOLDER] values):

import { Metadata } from 'next'
import { generateArticleSchema, generateFAQSchema, generateBreadcrumbSchema, injectSchema } from '@/lib/schema'
import Link from 'next/link'
import styles from '../blog-post.module.css'

export const metadata: Metadata = {
    title: '[SEO TITLE including keyword | MidSouth Dumpster Rentals]',
    description: '[155 char compelling meta description with keyword]',
    openGraph: {
        title: '[OG title]',
        description: '[OG description]',
        url: 'https://midsouthdumpsterms.com/blog/${slug}',
    },
}

const faqs = [
    { question: '[Question 1]', answer: '[Specific, detailed answer using business facts]' },
    { question: '[Question 2]', answer: '[Specific, detailed answer]' },
    { question: '[Question 3]', answer: '[Specific, detailed answer]' },
    { question: '[Question 4]', answer: '[Specific, detailed answer]' },
]

export default function BlogPost() {
    const articleSchema = generateArticleSchema(
        '[Title]',
        '[Description]',
        '${today}',
        'https://midsouthdumpsterms.com/opengraph-image.jpg',
        '${today}'
    )
    const faqSchema = generateFAQSchema(faqs)
    const breadcrumbSchema = generateBreadcrumbSchema([
        { name: 'Home', url: 'https://midsouthdumpsterms.com' },
        { name: 'Blog', url: 'https://midsouthdumpsterms.com/blog' },
        { name: '[Short Title]', url: 'https://midsouthdumpsterms.com/blog/${slug}' },
    ])
    return (
        <>
            <script type="application/ld+json" dangerouslySetInnerHTML={{ __html: injectSchema(articleSchema) }} />
            <script type="application/ld+json" dangerouslySetInnerHTML={{ __html: injectSchema(faqSchema) }} />
            <script type="application/ld+json" dangerouslySetInnerHTML={{ __html: injectSchema(breadcrumbSchema) }} />
            <article className={styles.article}>
                <div className="container container-narrow">
                    <Link href="/blog" className={styles.backLink}>&#8592; Back to Blog</Link>
                    <header className={styles.header}>
                        <span className={styles.category}>${category}</span>
                        <h1>[H1 — include keyword naturally]</h1>
                        <p className={styles.meta}>Updated ${todayFormatted}</p>
                    </header>
                    <div className={styles.content}>
                        <p className={styles.lead}>[Strong opening paragraph]</p>
                        [3-5 H2 sections with 2-4 paragraphs each. Include internal links and phone link naturally.]
                        <h2>Frequently Asked Questions</h2>
                        <div>
                            {faqs.map((faq, i) => (
                                <div key={i} style={{ marginBottom: '1.5rem' }}>
                                    <h3 style={{ fontSize: '1.1rem', marginBottom: '0.5rem' }}>{faq.question}</h3>
                                    <p>{faq.answer}</p>
                                </div>
                            ))}
                        </div>
                        <div className={styles.cta}>
                            <h3>Ready to Book Your Dumpster?</h3>
                            <p>Call <a href="tel:6013167891">601-316-7891</a> or book online &mdash; same-day delivery available 7 days a week.</p>
                            <a href="https://embed.survcart.com/?type=landing&co=irGaFVL6CggDRSyqIHNa&wsid=3u8ibIDlEWCk4uhSC1iS&sel=B77cgcBIlxlcSRgehUvF" target="_blank" rel="noopener noreferrer" className="btn btn-primary">Book Your Dumpster Now</a>
                        </div>
                    </div>
                </div>
            </article>
        </>
    )
}`;

return [{ json: { prompt, slug, keyword, category, location, date: today, dateFormatted: todayFormatted, row_number: rowNumber } }];

const agentOutput = $input.first().json.output || '';
const briefData = $('Build Content Brief').first().json;

// Remove any markdown code fences if present
let tsx = agentOutput
  .replace(/^```(?:tsx|typescript|jsx|js)?\n?/i, '')
  .replace(/\n?```$/i, '')
  .trim();

// SAFETY: Strip any invalid Next.js page exports that break TypeScript build
// Only 'export const metadata' and 'export default function' are valid in App Router pages
tsx = tsx.replace(/^export const (?!metadata\b)\w+[\s\S]*?(?=\n(?:export|import|const |function |\s*$)|$)/gm, '').trim();

// Remove any double blank lines created by the strip
tsx = tsx.replace(/\n{3,}/g, '\n\n');

const valid = tsx.length > 500 && tsx.includes('export default function BlogPost');

return [{
  json: {
    tsx_content: tsx,
    valid: valid,
    slug: briefData.slug,
    keyword: briefData.keyword,
    category: briefData.category,
    location: briefData.location,
    date: briefData.date,
    dateFormatted: briefData.dateFormatted,
    row_number: briefData.row_number,
    char_count: tsx.length
  }
}];

const data = $input.first().json;
const tsxContent = data.tsx_content;
const slug = data.slug;
const keyword = data.keyword;

// Base64 encode the TSX content
const base64Content = Buffer.from(tsxContent, 'utf8').toString('base64');

return [{
  json: {
    base64_content: base64Content,
    slug: slug,
    keyword: keyword,
    title: keyword.charAt(0).toUpperCase() + keyword.slice(1),
    file_path: `app/blog/${slug}/page.tsx`,
    commit_message: `feat: add blog post - ${keyword}`,
    github_repo: 'midsouthdumpsterms-blip/midsouthdumpsterms',
    date: data.date,
    dateFormatted: data.dateFormatted,
    row_number: data.row_number,
    tsx_content: tsxContent
  }
}];
